fn route_request(req: &Request) -> Option<&'static str> {
    let path = req.get_path();

    if path.starts_with("/api/") || path.starts_with("/api") {
        Some(BACKEND_API)
    } else if path.starts_with("/static/")
        || path.starts_with("/assets/")
        || path.starts_with("/images/")
        || path.ends_with(".css")
        || path.ends_with(".js")
        || path.ends_with(".png")
        || path.ends_with(".jpg")
        || path.ends_with(".svg")
        || path.ends_with(".woff2")
    {
        Some(BACKEND_SECONDARY)
    } else {
        Some(BACKEND_PRIMARY)
    }
}

fn find_backend_config(name: &str) -> Option<BackendConfig> {
    get_backend_configs().into_iter().find(|c| c.name == name)
}

fn sanitize_request(mut req: Request) -> Request {
    // Remove potentially dangerous headers that shouldn't be forwarded
    req.remove_header("X-Forwarded-For");
    req.remove_header("X-Real-IP");
    req.remove_header("X-Original-URL");
    req.remove_header("X-Rewrite-URL");

    // Ensure Host header is set properly based on the backend
    // (will be overridden per-backend below)

    // Validate the method - only allow safe/expected methods
    let allowed_methods = [
        Method::GET,
        Method::POST,
        Method::PUT,
        Method::DELETE,
        Method::PATCH,
        Method::HEAD,
        Method::OPTIONS,
    ];

    if !allowed_methods.contains(&req.get_method().clone()) {
        // We'll handle this in the main function by returning 405
    }

    req
}

fn add_security_headers(resp: &mut Response) {
    resp.set_header("X-Content-Type-Options", "nosniff");
    resp.set_header("X-Frame-Options", "DENY");
    resp.set_header("X-XSS-Protection", "1; mode=block");
    resp.set_header("Referrer-Policy", "strict-origin-when-cross-origin");
    resp.set_header(
        "Strict-Transport-Security",
        "max-age=31536000; includeSubDomains; preload",
    );
    resp.set_header(
        "Content-Security-Policy",
        "default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' data:; font-src 'self';",
    );
    // Remove server identification headers
    resp.remove_header("Server");
    resp.remove_header("X-Powered-By");
}

fn send_to_backend(mut req: Request, backend_name: &str) -> Result<Response, Error> {
    let config = find_backend_config(backend_name);

    if let Some(cfg) = config {
        // Set the Host header to match the backend
        req.set_header(header::HOST, cfg.host);

        // Use the pre-configured named backend
        let backend = Backend::from_name(backend_name)?;

        match req.send(backend) {
            Ok(mut resp) => {
                add_security_headers(&mut resp);
                Ok(resp)
            }
            Err(e) => {
                eprintln!("Backend request failed for {}: {:?}", backend_name, e);
                let mut resp = Response::from_status(StatusCode::BAD_GATEWAY);
                resp.set_body("Backend service unavailable");
                resp.set_header(header::CONTENT_TYPE, "text/plain; charset=utf-8");
                add_security_headers(&mut resp);
                Ok(resp)
            }
        }
    } else {
        let mut resp = Response::from_status(StatusCode::INTERNAL_SERVER_ERROR);
        resp.set_body("Backend configuration not found");
        resp.set_header(header::CONTENT_TYPE, "text/plain; charset=utf-8");
        add_security_headers(&mut resp);
        Ok(resp)
    }
}

fn handle_health_check() -> Response {
    let mut resp = Response::from_status(StatusCode::OK);
    resp.set_body("{\"status\":\"healthy\"}");
    resp.set_header(header::CONTENT_TYPE, "application/json; charset=utf-8");
    resp.set_header(header::CACHE_CONTROL, "no-store, no-cache, must-revalidate");
    add_security_headers(&mut resp);
    resp
}

fn handle_method_not_allowed() -> Response {
    let mut resp = Response::from_status(StatusCode::METHOD_NOT_ALLOWED);
    resp.set_body("Method Not Allowed");
    resp.set_header(header::CONTENT_TYPE, "text/plain; charset=utf-8");
    resp.set_header(header::ALLOW, "GET, POST, PUT, DELETE, PATCH, HEAD, OPTIONS");
    add_security_headers(&mut resp);
    resp
}

fn handle_not_found() -> Response {
    let mut resp = Response::from_status(StatusCode::NOT_FOUND);
    resp.set_body("Not Found");
    resp.set_header(header::CONTENT_TYPE, "text/plain; charset=utf-8");
    add_security_headers(&mut resp);
    resp
}

#[fastly::main]
fn main(req: Request) -> Result<Response, Error> {
    // Validate HTTP method
    let allowed_methods = [
        Method::GET,
        Method::POST,
        Method::PUT,
        Method::DELETE,
        Method::PATCH,
        Method::HEAD,
        Method::OPTIONS,
    ];

    if !allowed_methods.contains(&req.get_method().clone()) {
        return Ok(handle_method_not_allowed());
    }

    // Handle CORS preflight
    if req.get_method() == &Method::OPTIONS {
        let mut resp = Response::from_status(StatusCode::NO_CONTENT);
        resp.set_header("Access-Control-Allow-Origin", "*");
        resp.set_header(
            "Access-Control-Allow-Methods",
            "GET, POST, PUT, DELETE, PATCH, HEAD, OPTIONS",
        );
        resp.set_header(
            "Access-Control-Allow-Headers",
            "Content-Type, Authorization, Accept",
        );
        resp.set_header("Access-Control-Max-Age", "86400");
        add_security_headers(&mut resp);
        return Ok(resp);
    }

    // Health check endpoint
    let path = req.get_path().to_string();
    if path == "/health" || path == "/healthz" || path == "/__health" {
        return Ok(handle_health_check());
    }

    // Sanitize the request
    let req = sanitize_request(req);

    // Route to appropriate backend
    match route_request(&req) {
        Some(backend_name) => {
            println!(
                "Routing {} {} to backend: {}",
                req.get_method(),
                req.get_path(),
                backend_name
            );
            send_to_backend(req, backend_name)
        }
        None => Ok(handle_not_found()),
    }
}